#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int *array;
    int size;
    int capacity;
} DynamicStack;

void initStack(DynamicStack *s, int initialCapacity) {
    s->capacity = initialCapacity;
    s->size = 0;
    s->array = (int *)malloc(initialCapacity * sizeof(int));
}

void resize(DynamicStack *s) {
    s->capacity *= 2;
    s->array = (int *)realloc(s->array, s->capacity * sizeof(int));
}

void push(DynamicStack *s, int value) {
    if (s->size == s->capacity) {
        resize(s);  // O(n) operation
    }
    s->array[s->size++] = value;  // O(1)
}

int pop(DynamicStack *s) {
    if (s->size == 0) {
        printf("Stack Underflow\n");
        return -1;
    }
    // Optional: shrink if size < capacity/4
    if (s->size > 0 && s->size == s->capacity / 4) {
        s->capacity /= 2;
        s->array = (int *)realloc(s->array, s->capacity * sizeof(int));
    }
    return s->array[--s->size];  // O(1)
}

int main() {
    DynamicStack s;
    initStack(&s, 4);
    push(&s, 10); push(&s, 20); push(&s, 30);
    printf("Popped: %d\n", pop(&s));  // 30
    return 0;
}

import ctypes

class DynamicArray:
    def __init__(self, capacity=1):
        self.size = 0
        self.capacity = capacity
        self.array = (capacity * ctypes.py_object)()

    def __len__(self):
        return self.size

    def append(self, value):
        # Resize if needed (double capacity)
        if self.size == self.capacity:
            self._resize(2 * self.capacity)
        self.array[self.size] = value
        self.size += 1

    def _resize(self, new_capacity):
        # Create new array and copy elements
        new_array = (new_capacity * ctypes.py_object)()
        for i in range(self.size):
            new_array[i] = self.array[i]
        self.array = new_array
        self.capacity = new_capacity

    def __getitem__(self, index):
        if 0 <= index < self.size:
            return self.array[index]
        raise IndexError("Index out of range")

